from typing import List

class Solution:
    def maxDepthAfterSplit(self, seq: str) -> List[int]:
        A, B = 0, 0
        res = []
        for c in seq:
            if c == '(':
                if A <= B:
                    A += 1
                    res.append(0)
                else:
                    B += 1
                    res.append(1)
            else:
                if A > B:
                    A -= 1
                    res.append(0)
                else:
                    B -= 1
                    res.append(1)
        return res
```
